import React, { useState } from 'react';

export default function TagInput({ initialTags = [], onTagsChange }) {
  const [tags, setTags] = useState(initialTags);
  const [inputVal, setInputVal] = useState("");
  const [isDuplicate, setIsDuplicate] = useState(false);

  const handleKeyDown = (e) => {
    if (e.key === "Enter" || e.key === ",") {
      e.preventDefault();
      const cleaned = inputVal.trim().replace(/,/g, '');

      if (!cleaned) return;

      if (tags.includes(cleaned)) {
        setIsDuplicate(true);
        return;
      }

      const updated = [...tags, cleaned];
      setTags(updated);
      setInputVal("");
      setIsDuplicate(false);
      if (onTagsChange) onTagsChange(updated);
    }
  };

  const removeTag = (tagToRemove) => {
    const updated = tags.filter(tag => tag !== tagToRemove);
    setTags(updated);
    if (onTagsChange) onTagsChange(updated);
  };

  return (
    <div className="w-full max-w-md">
      <div className={`flex flex-wrap items-center gap-2 p-2 border-2 rounded-xl bg-white focus-within:ring-2 focus-within:ring-purple-200 transition ${
        isDuplicate ? 'border-red-400 focus-within:border-red-400' : 'border-gray-200 focus-within:border-purple-500'
      }`}>
        {/* Render Active Tag Badges */}
        {tags.map((tag, idx) => (
          <span key={idx} className="flex items-center gap-1.5 bg-purple-50 text-purple-700 text-sm font-semibold px-2.5 py-1 rounded-lg border border-purple-100">
            <span>{tag}</span>
            <button onClick={() => removeTag(tag)} className="text-purple-400 hover:text-purple-600 focus:outline-none">
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </span>
        ))}

        {/* Input box */}
        <input
          type="text"
          value={inputVal}
          onChange={(e) => { setInputVal(e.target.value); setIsDuplicate(false); }}
          onKeyDown={handleKeyDown}
          placeholder={tags.length === 0 ? "Add tag..." : ""}
          className="flex-1 min-w-[120px] py-1 text-sm text-gray-700 bg-transparent outline-none"
        />
      </div>
      {isDuplicate && (
        <p className="text-red-500 text-xs mt-1.5 font-medium">Tag already exists!</p>
      )}
    </div>
  );
}
